165	// ── Lexer ───────────────────────────────────────────────────
166	
167	/// Read one shell word starting at `*i`, advancing `*i` past it and `*line`
168	/// over any embedded newlines. Quoted segments and `${...}` parameter
169	/// expansions are consumed as part of the word; an embedded `$(` command
170	/// substitution STOPS the word so the caller's lexer scans the substituted
171	/// command at its own command position.
172	pub(crate) fn zrbtdru_read_word(chars: &[char], i: &mut usize, line: &mut usize) -> String {
173	    let n = chars.len();
174	    let mut word = String::new();
175	    while *i < n {
176	        let c = chars[*i];
177	        match c {
178	            ' ' | '\t' | '\r' | '\n' => break,
179	            ';' | '|' | '&' | '<' | '>' | '(' | ')' | '`' | '#' => break,
180	            '\'' => {
181	                word.push(c);
182	                *i += 1;
183	                while *i < n && chars[*i] != '\'' {
184	                    if chars[*i] == '\n' {
185	                        *line += 1;
186	                    }
187	                    word.push(chars[*i]);
188	                    *i += 1;
189	                }
190	                if *i < n {
191	                    word.push(chars[*i]);
192	                    *i += 1;
193	                }
194	            }
195	            '"' => {
196	                word.push(c);
197	                *i += 1;
198	                while *i < n && chars[*i] != '"' {
199	                    if chars[*i] == '\\' && *i + 1 < n {
200	                        word.push(chars[*i]);
201	                        word.push(chars[*i + 1]);
202	                        *i += 2;
203	                        continue;
204	                    }
205	                    if chars[*i] == '\n' {
206	                        *line += 1;
207	                    }
208	                    word.push(chars[*i]);
209	                    *i += 1;
210	                }
211	                if *i < n {
212	                    word.push(chars[*i]);
213	                    *i += 1;
214	                }
215	            }
216	            '$' if *i + 1 < n && chars[*i + 1] == '(' => break,
217	            '$' if *i + 1 < n && chars[*i + 1] == '{' => {
218	                word.push('$');
219	                *i += 1;
220	                let mut depth = 0usize;
221	                while *i < n {
222	                    let d = chars[*i];
223	                    if d == '\n' {
224	                        *line += 1;
225	                    }
226	                    word.push(d);
227	                    *i += 1;
228	                    if d == '{' {
229	                        depth += 1;
230	                    } else if d == '}' {
231	                        depth -= 1;
232	                        if depth == 0 {
233	                            break;
234	                        }
235	                    }
236	                }
237	            }
238	            _ => {
239	                word.push(c);
240	                *i += 1;
241	            }
242	        }
243	    }
244	    word
245	}
246	
247	/// Classify a word as transparent or value-introducing when it sits in command
248	/// position. `Some(true)` — a keyword whose successor is itself a command
249	/// (`if`, `then`, `while`, …). `Some(false)` — a keyword whose successor is a
250	/// value, not a command (`for`, `case`, `in`, …). `None` — not a keyword.
251	pub(crate) fn zrbtdru_keyword_kind(word: &str) -> Option<bool> {
252	    match word {
253	        "if" | "elif" | "while" | "until" | "then" | "else" | "do" | "!"
254	        | "time" | "fi" | "done" | "esac" => Some(true),
255	        "for" | "select" | "case" | "in" | "function" => Some(false),
256	        _ => None,
257	    }
258	}
259	
260	/// True when `word` is a `NAME=`, `NAME+=`, or `NAME[idx]=` assignment prefix —
261	/// a command may still follow on the same line (`FOO=bar cmd`), so command
262	/// position is preserved across it.
263	pub(crate) fn zrbtdru_is_assignment(word: &str) -> bool {
264	    let bytes = word.as_bytes();
265	    if bytes.is_empty() {
266	        return false;
267	    }
268	    let first = bytes[0] as char;
269	    if !(first.is_ascii_alphabetic() || first == '_') {
270	        return false;
271	    }
272	    let mut k = 1;
273	    while k < bytes.len() {
274	        let ch = bytes[k] as char;
275	        if ch == '=' {
276	            return true;
277	        }
278	        if ch == '+' && k + 1 < bytes.len() && bytes[k + 1] == b'=' {
279	            return true;
280	        }
281	        if ch == '[' {
282	            return word.contains("]=");
283	        }
284	        if !(ch.is_ascii_alphanumeric() || ch == '_') {
285	            return false;
286	        }
287	        k += 1;
288	    }
289	    false
290	}
291	
292	/// Advance `*i` past a balanced run of parentheses, tracking newlines in
293	/// `*line`. `depth` is the count of opening parens already consumed by the
294	/// caller; scanning ends when it returns to zero. Quoted segments are skipped
295	/// so parens inside strings do not affect the balance — covering array literals
296	/// `NAME=( … )` and nested arithmetic `$(( ( … ) ))`.
297	pub(crate) fn zrbtdru_skip_balanced_parens(chars: &[char], i: &mut usize, line: &mut usize, mut depth: usize) {
298	    let n = chars.len();
299	    while *i < n && depth > 0 {
300	        match chars[*i] {
301	            '(' => depth += 1,
302	            ')' => depth -= 1,
303	            '\n' => *line += 1,
304	            '\'' => {
305	                *i += 1;
306	                while *i < n && chars[*i] != '\'' {
307	                    if chars[*i] == '\n' {
308	                        *line += 1;
309	                    }
310	                    *i += 1;
311	                }
312	            }
313	            '"' => {
314	                *i += 1;
315	                while *i < n && chars[*i] != '"' {
316	                    if chars[*i] == '\\' && *i + 1 < n {
317	                        *i += 2;
318	                        continue;
319	                    }
320	                    if chars[*i] == '\n' {
321	                        *line += 1;
322	                    }
323	                    *i += 1;
324	                }
325	            }
326	            _ => {}
327	        }
328	        *i += 1;
329	    }
330	}
331	
332	/// Extract every command-position token from a bash source string, paired with
333	/// its 1-based line number. A token is in command position at the start of the
334	/// script and after any command separator (`;`, `|`, `&`, `&&`, `||`, newline,
335	/// `(`, `$(`, `` ` ``, an open brace group) and after a transparent keyword.
336	/// Assignments, redirections, `[[ ]]` test contents, comments, here-doc bodies,
337	/// and arithmetic `(( ))` / `$(( ))` are excluded.
338	pub(crate) fn zrbtdru_command_words(src: &str) -> Vec<(usize, String)> {
339	    let chars: Vec<char> = src.chars().collect();
340	    let n = chars.len();
341	    let mut out: Vec<(usize, String)> = Vec::new();
342	    let mut i = 0usize;
343	    let mut line = 1usize;
344	    let mut cmd_pos = true;
345	    let mut paren_depth = 0usize;
346	    let mut in_dbracket = false;
347	    let mut pending_heredoc: Option<String> = None;
348	    // case…esac nesting. Each frame tracks the position within a `case`:
349	    // 0 = subject (between `case` and `in`), 1 = pattern (suppress recording;
350	    // `|` is alternation, not a pipe), 2 = branch body (record commands).
351	    let mut case_stack: Vec<u8> = Vec::new();
352	
353	    while i < n {
354	        let c = chars[i];
355	
356	        if c == '\n' {
357	            i += 1;
358	            line += 1;
359	            cmd_pos = true;
360	            if let Some(delim) = pending_heredoc.take() {
361	                loop {
362	                    let start = i;
363	                    while i < n && chars[i] != '\n' {
364	                        i += 1;
365	                    }
366	                    let body: String = chars[start..i].iter().collect();
367	                    let had_nl = i < n;
368	                    if had_nl {
369	                        i += 1;
370	                        line += 1;
371	                    }
372	                    if body.trim() == delim {
373	                        break;
374	                    }
375	                    if !had_nl {
376	                        break;
377	                    }
378	                }
379	            }
380	            continue;
381	        }
382	        if c == ' ' || c == '\t' || c == '\r' {
383	            i += 1;
384	            continue;
385	        }
386	        if c == '\\' && i + 1 < n && chars[i + 1] == '\n' {
387	            i += 2;
388	            line += 1;
389	            continue;
390	        }
391	        if c == '#' {
392	            while i < n && chars[i] != '\n' {
393	                i += 1;
394	            }
395	            continue;
396	        }
397	        if c == ';' {
398	            i += 1;
399	            if i < n && chars[i] == ';' {
400	                i += 1;
401	                // `;;` ends a case branch — the next token opens a new pattern.
402	                if let Some(top) = case_stack.last_mut() {
403	                    *top = 1;
404	                }
405	                cmd_pos = false;
406	                continue;
407	            }
408	            if !in_dbracket {
409	                cmd_pos = true;
410	            }
411	            continue;
412	        }
413	        if c == '|' {
414	            i += 1;
415	            if i < n && chars[i] == '|' {
416	                i += 1;
417	            }
418	            // Within a case pattern `|` is alternation, not a pipe.
419	            if case_stack.last() == Some(&1) {
420	                continue;
421	            }
422	            if !in_dbracket {
423	                cmd_pos = true;
424	            }
425	            continue;
426	        }
427	        if c == '&' {
428	            if i + 1 < n && chars[i + 1] == '>' {
429	                i += 2;
430	                if i < n && chars[i] == '>' {
431	                    i += 1;
432	                }
433	                cmd_pos = false;
434	                continue;
435	            }
436	            i += 1;
437	            if i < n && chars[i] == '&' {
438	                i += 1;
439	            }
440	            if !in_dbracket {
441	                cmd_pos = true;
442	            }
443	            continue;
444	        }
445	        if c == '<' {
446	            if i + 1 < n && chars[i + 1] == '<' {
447	                if i + 2 < n && chars[i + 2] == '<' {
448	                    i += 3;
449	                    cmd_pos = false;
450	                    continue;
451	                }
452	                i += 2;
453	                if i < n && chars[i] == '-' {
454	                    i += 1;
455	                }
456	                while i < n && (chars[i] == ' ' || chars[i] == '\t') {
457	                    i += 1;
458	                }
459	                let mut delim = String::new();
460	                let quote = if i < n && (chars[i] == '\'' || chars[i] == '"') {
461	                    let q = chars[i];
462	                    i += 1;
463	                    Some(q)
464	                } else {
465	                    None
466	                };
467	                while i < n {
468	                    let d = chars[i];
469	                    match quote {
470	                        Some(qc) => {
471	                            if d == qc {
472	                                i += 1;
473	                                break;
474	                            }
475	                            delim.push(d);
476	                            i += 1;
477	                        }
478	                        None => {
479	                            if d == ' ' || d == '\t' || d == '\n' || d == ';'
480	                                || d == '&' || d == '|' || d == '<' || d == '>'
481	                                || d == '(' || d == ')'
482	                            {
483	                                break;
484	                            }
485	                            if d == '\\' {
486	                                i += 1;
487	                                continue;
488	                            }
489	                            delim.push(d);
490	                            i += 1;
491	                        }
492	                    }
493	                }
494	                if !delim.is_empty() {
495	                    pending_heredoc = Some(delim);
496	                }
497	                cmd_pos = false;
498	                continue;
499	            }
500	            i += 1;
501	            if i < n && chars[i] == '&' {
502	                i += 1;
503	            }
504	            cmd_pos = false;
505	            continue;
506	        }
507	        if c == '>' {
508	            i += 1;
509	            if i < n && (chars[i] == '>' || chars[i] == '&') {
510	                i += 1;
511	            }
512	            cmd_pos = false;
513	            continue;
514	        }
515	        if c == '(' {
516	            if i + 1 < n && chars[i + 1] == '(' {
517	                // Arithmetic `(( … ))` — not a command list.
518	                i += 2;
519	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
520	                cmd_pos = false;
521	                continue;
522	            }
523	            i += 1;
524	            paren_depth += 1;
525	            cmd_pos = true;
526	            continue;
527	        }
528	        if c == ')' {
529	            i += 1;
530	            if paren_depth > 0 {
531	                paren_depth -= 1;
532	                cmd_pos = false;
533	            } else if case_stack.last() == Some(&1) {
534	                // Pattern terminator — the branch body's command list follows.
535	                if let Some(top) = case_stack.last_mut() {
536	                    *top = 2;
537	                }
538	                cmd_pos = true;
539	            } else {
540	                cmd_pos = true;
541	            }
542	            continue;
543	        }
544	        if c == '`' {
545	            i += 1;
546	            cmd_pos = true;
547	            continue;
548	        }
549	        if c == '$' {
550	            if i + 1 < n && chars[i + 1] == '(' {
551	                if i + 2 < n && chars[i + 2] == '(' {
552	                    // Arithmetic substitution `$(( … ))` — not a command.
553	                    i += 3;
554	                    zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
555	                    cmd_pos = false;
556	                    continue;
557	                }
558	                i += 2;
559	                paren_depth += 1;
560	                cmd_pos = true;
561	                continue;
562	            }
563	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
564	            cmd_pos = false;
565	            continue;
566	        }
567	        if c == '{' {
568	            if i + 1 < n && (chars[i + 1] == ' ' || chars[i + 1] == '\t' || chars[i + 1] == '\n') {
569	                i += 1;
570	                cmd_pos = true;
571	                continue;
572	            }
573	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
574	            cmd_pos = false;
575	            continue;
576	        }
577	        if c == '}' {
578	            i += 1;
579	            continue;
580	        }
581	
582	        let word_line = line;
583	        let word = zrbtdru_read_word(&chars, &mut i, &mut line);
584	        if word.is_empty() {
585	            i += 1;
586	            continue;
587	        }
588	        if word == "[[" {
589	            if cmd_pos {
590	                in_dbracket = true;
591	            }
592	            cmd_pos = false;
593	            continue;
594	        }
595	        if word == "]]" {
596	            in_dbracket = false;
597	            cmd_pos = false;
598	            continue;
599	        }
600	        if in_dbracket {
601	            continue;
602	        }
603	        // case…esac structure — tracked regardless of command position so that
604	        // branch patterns (which sit at command position) are not mistaken for
605	        // commands.
606	        if word == "case" {
607	            case_stack.push(0);
608	            cmd_pos = false;
609	            continue;
610	        }
611	        if word == "esac" {
612	            case_stack.pop();
613	            cmd_pos = false;
614	            continue;
615	        }
616	        if word == "in" && case_stack.last() == Some(&0) {
617	            if let Some(top) = case_stack.last_mut() {
618	                *top = 1;
619	            }
620	            cmd_pos = false;
621	            continue;
622	        }
623	        if case_stack.last() == Some(&1) {
624	            // Matching a case pattern — suppress; the pattern is not a command.
625	            cmd_pos = false;
626	            continue;
627	        }
628	        if !cmd_pos {
629	            continue;
630	        }
631	        if zrbtdru_is_assignment(&word) {
632	            // `NAME=( … )` array literal — the elements are data, not commands.
633	            let mut j = i;
634	            while j < n && (chars[j] == ' ' || chars[j] == '\t') {
635	                j += 1;
636	            }
637	            if j < n && chars[j] == '(' {
638	                i = j + 1;
639	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 1);
640	            }
641	            continue;
642	        }
643	        match zrbtdru_keyword_kind(&word) {
644	            Some(true) => continue,
645	            Some(false) => {
646	                cmd_pos = false;
647	                continue;
648	            }
649	            None => {}
650	        }
651	        out.push((word_line, word));
652	        cmd_pos = false;
653	    }
654	    out
655	}
656	
657	// ── Function collection and classification ──────────────────
658	
659	/// Harvest locally-defined function names from one source into `out`. Matches
660	/// both `name() {` and `function name` forms.
661	pub(crate) fn zrbtdru_collect_functions(src: &str, out: &mut BTreeSet<String>) {
662	    for raw in src.lines() {
663	        let trimmed = raw.trim_start();
664	        let rest = if let Some(after) = trimmed.strip_prefix("function ") {
665	            after.trim_start()
666	        } else {
667	            trimmed
668	        };
669	        let mut name = String::new();
670	        for ch in rest.chars() {
671	            if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
672	                name.push(ch);
673	            } else {
674	                break;
675	            }
676	        }
677	        if name.is_empty() {
678	            continue;
679	        }
680	        let after_name = rest[name.len()..].trim_start();
681	        if after_name.starts_with("()") || trimmed.starts_with("function ") {
682	            out.insert(name);
683	        }
684	    }
685	}
686	
687	/// Classify a command-position token. Returns `Some(detail)` when it violates
688	/// the domain's discipline, `None` when it is permitted. Dynamic tokens
689	/// (containing an expansion or quote) cannot be statically named and are
690	/// skipped.
691	pub(crate) fn zrbtdru_classify(
692	    command: &str,
693	    locals: &BTreeSet<String>,
694	    domain: zrbtdru_Domain,
695	) -> Option<String> {
696	    if command.is_empty() {
697	        return None;
698	    }
699	    if command.contains('$')
700	        || command.contains('`')
701	        || command.contains('"')
702	        || command.contains('\'')
703	    {
704	        return None;
705	    }
706	    let base = command.rsplit('/').next().unwrap_or(command);
707	    if ZRBTDRU_BUILTINS.contains(&base) {
708	        return None;
709	    }
710	    if locals.contains(command) || locals.contains(base) {
711	        return None;
712	    }
713	    if ZRBTDRU_POSIX_FLOOR.contains(&base) {
714	        return None;
715	    }
716	    if ZRBTDRU_DECLARED_DEPS.contains(&base) {
717	        return None;
718	    }
719	    match domain {
720	        zrbtdru_Domain::Kit => {
721	            for ev in ZRBTDRU_EVICTIONS {
722	                if ev.command == base {
723	                    return Some(format!("evicted command — use {}", ev.replacement));
724	                }
725	            }
726	            Some("unknown command — not in POSIX floor or RBS0 declared dependencies".to_string())
727	        }
728	        zrbtdru_Domain::Gcb => {
729	            if ZRBTDRU_GCB_EXTRA.contains(&base) {
730	                return None;
731	            }
732	            for ev in ZRBTDRU_EVICTIONS {
733	                if ev.command == base {
734	                    return None;
735	                }
736	            }
737	            Some("unknown command — not in the GCB allowlist".to_string())
738	        }
739	    }
740	}
741	
742	// ── Corpus walk and scan ────────────────────────────────────
743	
744	/// Recursively collect every `*.sh` file under `dir` into `out`.
745	fn zrbtdru_walk_sh(dir: &Path, out: &mut Vec<PathBuf>) {
746	    let entries = match std::fs::read_dir(dir) {
747	        Ok(e) => e,
748	        Err(_) => return,
749	    };
750	    for entry in entries.flatten() {
751	        let path = entry.path();
752	        if path.is_dir() {
753	            let abandoned = path
754	                .file_name()
755	                .and_then(|s| s.to_str())
756	                .map(|s| s.starts_with(ZRBTDRU_ABANDONED_DIR_PREFIX))
757	                .unwrap_or(false);
758	            if abandoned {
759	                continue;
760	            }
761	            zrbtdru_walk_sh(&path, out);
762	        } else if path.extension().and_then(|e| e.to_str()) == Some(ZRBTDRU_SH_EXT) {
763	            out.push(path);
764	        }
765	    }
766	}
767	
768	/// True when `path` lies under a Google Cloud Build job directory (any path
769	/// component beginning with the rbgj prefix).
770	fn zrbtdru_is_gcb(path: &Path) -> bool {
771	    path.components().any(|comp| {
772	        comp.as_os_str()
773	            .to_str()
774	            .map(|s| s.starts_with(ZRBTDRU_GCB_DIR_PREFIX))
775	            .unwrap_or(false)
776	    })
777	}
778	
779	/// Walk the corpus, collect functions across all of it, then scan the files
780	/// belonging to `domain`, returning every finding sorted by file and line.
781	fn zrbtdru_scan_domain(tools: &Path, domain: zrbtdru_Domain) -> Result<Vec<zrbtdru_Finding>, String> {
782	    let mut files: Vec<PathBuf> = Vec::new();
783	    zrbtdru_walk_sh(tools, &mut files);
784	    files.sort();
785	
786	    let mut sources: Vec<(PathBuf, String)> = Vec::with_capacity(files.len());
787	    for f in &files {
788	        let src = std::fs::read_to_string(f)
789	            .map_err(|e| format!("read {} failed: {}", f.display(), e))?;
790	        sources.push((f.clone(), src));
791	    }
792	
793	    let mut locals: BTreeSet<String> = BTreeSet::new();
794	    for (_, src) in &sources {
795	        zrbtdru_collect_functions(src, &mut locals);
796	    }
797	
798	    let root = tools.parent().unwrap_or(tools);
799	    let mut findings: Vec<zrbtdru_Finding> = Vec::new();
800	    for (path, src) in &sources {
801	        let is_gcb = zrbtdru_is_gcb(path);
802	        let in_domain = match domain {
803	            zrbtdru_Domain::Kit => !is_gcb,
804	            zrbtdru_Domain::Gcb => is_gcb,
805	        };
806	        if !in_domain {
807	            continue;
808	        }
809	        let rel = path.strip_prefix(root).unwrap_or(path).display().to_string();
810	        for (line, command) in zrbtdru_command_words(src) {
811	            if let Some(detail) = zrbtdru_classify(&command, &locals, domain) {
812	                findings.push(zrbtdru_Finding {
813	                    file: rel.clone(),
814	                    line,
815	                    command,
816	                    detail,
817	                });
818	            }
819	        }
820	    }
821	    Ok(findings)
822	}
823	
824	/// Render findings as a stable one-per-line report.
825	fn zrbtdru_render(findings: &[zrbtdru_Finding]) -> String {
826	    let mut report = String::new();
827	    for f in findings {
828	        report.push_str(&format!("{}:{}: {} — {}\n", f.file, f.line, f.command, f.detail));
829	    }
830	    report
831	}
832	
833	/// Drive one domain's scan, persist a findings trace into the case dir, and
834	/// fail the verdict when any violation remains.
835	fn zrbtdru_run_domain(dir: &Path, domain: zrbtdru_Domain, label: &str) -> rbtdre_Verdict {
836	    let root = match std::env::current_dir() {
837	        Ok(r) => r,
838	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
839	    };
840	    let tools = root.join(ZRBTDRU_TOOLS_SUBDIR);
841	    let findings = match zrbtdru_scan_domain(&tools, domain) {
842	        Ok(f) => f,
843	        Err(e) => return rbtdre_Verdict::Fail(e),
844	    };
845	    let report = zrbtdru_render(&findings);
846	    let _ = std::fs::write(dir.join(format!("cupel-{}-findings.txt", label)), &report);
847	
848	    if findings.is_empty() {
849	        rbtdre_Verdict::Pass
850	    } else {
851	        rbtdre_Verdict::Fail(format!(
852	            "{} BCG command-discipline violation(s) in {}-bash:\n{}",
853	            findings.len(),
854	            label,
855	            report
856	        ))
857	    }
858	}
859	
860	// ── Cases and fixture ───────────────────────────────────────
861	
862	fn rbtdru_kit_bash(dir: &Path) -> rbtdre_Verdict {
863	    zrbtdru_run_domain(dir, zrbtdru_Domain::Kit, "kit")
864	}
865	
866	fn rbtdru_gcb_bash(dir: &Path) -> rbtdre_Verdict {
867	    zrbtdru_run_domain(dir, zrbtdru_Domain::Gcb, "gcb")
868	}
869	
870	pub static RBTDRU_CASES_CUPEL: &[rbtdre_Case] = &[
871	    case!(rbtdru_kit_bash),
872	    case!(rbtdru_gcb_bash),
873	];
874	
875	pub static RBTDRU_FIXTURE_CUPEL: rbtdre_Fixture = rbtdre_Fixture {
876	    name: RBTDRM_FIXTURE_CUPEL,
877	    disposition: rbtdre_Disposition::Independent,
878	    setup: None,
879	    teardown: None,
880	    cases: RBTDRU_CASES_CUPEL,
881	};
882

