697	/// Harvest locally-defined function names from one source into `out`. Matches
698	/// both `name() {` and `function name` forms.
699	pub(crate) fn zrbtdru_collect_functions(src: &str, out: &mut BTreeSet<String>) {
700	    for raw in src.lines() {
701	        let trimmed = raw.trim_start();
702	        let rest = if let Some(after) = trimmed.strip_prefix("function ") {
703	            after.trim_start()
704	        } else {
705	            trimmed
706	        };
707	        let mut name = String::new();
