    command: &str,
    locals: &BTreeSet<String>,
    domain: zrbtdru_Domain,
) -> Option<String> {
    if command.is_empty() {
        return None;
    }
    if command.contains('$')
        || command.contains('`')
        || command.contains('"')
        || command.contains('\'')
    {
        return None;
    }
    let base = command.rsplit('/').next().unwrap_or(command);

